return null;

// msg.payload = {"event":"RFID_OK","name":"...","uid":"..."} (JSON ou string)
let p = msg.payload;
if (typeof p === "string") {
  try { p = JSON.parse(p); } catch(e) { p = { raw: msg.payload }; }
}

const row = {
  time: new Date().toLocaleString("fr-FR"),
  name: p.name || "Unknown",
  uid:  p.uid  || "",
  event: p.event || "RFID"
};

let hist = global.get("rfid_hist") || [];
if (!Array.isArray(hist)) hist = [];

hist.push(row);
// garder max 20 (du plus ancien au plus récent)
if (hist.length > 20) hist = hist.slice(hist.length - 20);

global.set("rfid_hist", hist);

// (optionnel) sortir vers debug
msg.payload = row;
return msg;

