function normUid(u){
  return (""+u).trim().toUpperCase()
    .replace(/[^0-9A-F]/g," ")
    .replace(/\s+/g," ")
    .trim();
}

msg.statusCode = 200;
msg.headers = {
  "Content-Type":"application/json; charset=utf-8",
  "Cache-Control":"no-store, no-cache, must-revalidate, proxy-revalidate",
  "Pragma":"no-cache",
  "Expires":"0"
};

let { uid, name, enabled, master } = msg.payload || {};
uid = normUid(uid);
name = (""+(name||"")).trim();

if (!uid || uid.split(" ").length !== 4){
  msg.statusCode = 400;
  msg.payload = { ok:false, error:"UID invalide (ex: 8F AB 8D C2)" };
  return msg;
}
if (!name) name = "Unknown";

let db = global.get("cards_db") || [];
if (!Array.isArray(db)) db = [];

if (db.some(x => normUid(x.uid) === uid)){
  msg.statusCode = 409;
  msg.payload = { ok:false, error:"UID existe déjà" };
  return msg;
}

db.push({
  uid,
  name,
  enabled: enabled !== false,
  master: !!master
});

global.set("cards_db", db);

msg.payload = { ok:true };
return msg;

