  msg.statusCode = 400;
  msg.payload = { ok:false, error:"uid invalide" };
  return msg;
}

let c = db.find(x => normUid(x.uid) === uid);
if (!c){
  c = { uid, name:"Unknown", enabled:true, master:false };
  db.push(c);
}

if (msg.payload.name !== undefined) c.name = (""+msg.payload.name).trim() || "Unknown";
if (msg.payload.enabled !== undefined) c.enabled = !!msg.payload.enabled;
if (msg.payload.master !== undefined) c.master = !!msg.payload.master;

c.uid = uid;

global.set("cards_db", db);

