return msg;

function normUid(u){
  return (""+u).trim().toUpperCase()
    .replace(/[^0-9A-F]/g," ")
    .replace(/\s+/g," ")
    .trim();
}

msg.statusCode = 200;
msg.headers = {
  "Content-Type":"application/json; charset=utf-8",
  "Cache-Control":"no-store, no-cache, must-revalidate, proxy-revalidate",
  "Pragma":"no-cache",
  "Expires":"0"
};

const uid = normUid((msg.req?.query?.uid) || "");
let db = global.get("cards_db") || [];
if (!Array.isArray(db)) db = [];

const before = db.length;
db = db.filter(x => normUid(x.uid) !== uid);

global.set("cards_db", db);

msg.payload = { ok:true, removed: before - db.length };
return msg;

let db = global.get("cards_db") || [];
if (!Array.isArray(db)) db = [];

// Important : publier master aussi
msg.topic = "sas/cards";
msg.payload = JSON.stringify(db);
msg.retain = true;     // pour que l’ESP32 reçoive même après reboot
msg.qos = 0;
return msg;
